package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void testGetCurrencyCode() throws Exception {
    Class<?> clazz = LineItem.class;
    Constructor<?> constructor = clazz.getDeclaredConstructor(String.class, int.class, long.class, String.class);
    constructor.setAccessible(true);
    Object lineItem = constructor.newInstance("itemName", 2, 1000L, "USD");

    String actualCurrencyCode = (String) clazz.getMethod("getCurrencyCode").invoke(lineItem);
    assertEquals("USD", actualCurrencyCode);
  }
}
